// src/components/NavBtn.jsx

export default function NavBtn({ onClick, label, disabled }) {
  return (
    <button
      onClick={onClick}
      disabled={disabled}
      style={{
        background: disabled
          ? "rgba(255,255,255,0.06)"
          : "linear-gradient(135deg,rgba(124,58,237,0.8),rgba(37,99,235,0.8))",
        border: disabled
          ? "1px solid rgba(255,255,255,0.08)"
          : "1px solid rgba(167,139,250,0.3)",
        color: disabled ? "rgba(255,255,255,0.2)" : "#fff",
        borderRadius: 12,
        padding: "10px 22px",
        cursor: disabled ? "default" : "pointer",
        fontWeight: 800,
        fontSize: 14,
        fontFamily: "'Nunito',sans-serif",
        transition: "all 0.2s",
        boxShadow: disabled ? "none" : "0 4px 16px rgba(124,58,237,0.4)",
      }}
    >
      {label}
    </button>
  );
}
